import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { FaHome, FaPills, FaCalendarAlt, FaUser, FaCog } from 'react-icons/fa';

const BottomNavigation = () => {
  const { t } = useTranslation();
  const location = useLocation();

  const navItems = [
    { path: '/', label: t('home'), icon: FaHome },
    { path: '/medicines', label: t('medicines'), icon: FaPills },
    { path: '/availability', label: t('availability'), icon: FaCalendarAlt },
    { path: '/profile', label: t('profile'), icon: FaUser },
    { path: '/settings', label: t('settings'), icon: FaCog }
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 shadow-2xl z-50">
      <div className="flex justify-between items-center h-20 px-2 gap-1">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;
          
          return (
            <Link
              key={item.path}
              to={item.path}
              className={`flex flex-col items-center justify-center flex-1 py-3 px-1 mx-0.5 rounded-lg transition-all duration-300 ease-in-out group no-underline focus:outline-none ${
                isActive
                  ? 'bg-blue-50 transform scale-105'
                  : 'hover:scale-102 hover:bg-gray-50'
              }`}
              style={{ textDecoration: 'none', minWidth: 0, maxWidth: '70px' }}
            >
              <div className={`flex items-center justify-center w-10 h-10 rounded-lg transition-all duration-300 ease-in-out ${
                isActive 
                  ? 'bg-blue-500 shadow-md' 
                  : 'bg-transparent group-hover:bg-blue-100'
              }`}>
                <Icon className={`transition-all duration-300 ease-in-out ${
                  isActive 
                    ? 'text-lg text-white' 
                    : 'text-lg text-gray-600 group-hover:text-blue-500'
                }`} />
              </div>
              <span className={`block w-full text-xs font-medium mt-1 transition-all duration-300 ease-in-out text-center ${
                isActive 
                  ? 'text-blue-500 font-semibold' 
                  : 'text-gray-500 group-hover:text-blue-500'
              }`} style={{lineHeight: '1.1', fontSize: '10px'}}>
                {item.label}
              </span>
            </Link>
          );
        })}
      </div>
    </div>
  );
};

export default BottomNavigation;
